; C1:CA72

C1CA72_RefreshBattlePsiSelection:
    rep #$31
    phd
    pha
    tdc
    adc.w #$FFEE
    tcd
    pla
    stx $02
    sta $04
    jsl C3E4D4_EnterWindowUpdateScope
    lda $8958
    asl A
    tax
    lda $88E4,X
    ldy.w #$0052
    jsl C08FF7_ResolveIndexedPointerOffset
    clc
    adc.w #$8650
    clc
    adc.w #$0010
    tax
    stx $10
    lda $0000,X
    tay
    sty $0E
    lda $8958
    jsl EF0115_ClearBattleSpriteRowEffects
    jsl C3E4E0_TickWindowWithoutInstantPrinting
    lda $9D16
