    jsr C1163C_FinalizeSelectionMenu
    ldy $0E
    tya
    ldx $10
    sta $0000,X
    jsr C104D8_GetCurrentTextContextRowState
    tax
    lda.w #$0000
    jsl C438A5_SetActiveWindowDescriptorCursorFields
    lda $02
    jsr C10FEA_SetActiveWindowTileAttributes
    lda $04
    sta $04
    asl A
    adc $04
    asl A
    adc $04
    asl A
    adc $04
